// =============================================================================
// Preparação de Dados Sazonais — v2
// Heurística Determinística com Janelamento Sazonal
//
// MUDANÇAS desta versão:
//   1. Horizonte: mês atual + próximos 2 meses (3 meses começando em "agora")
//   2. Validação global: mês ANTERIOR ao atual deve existir no histórico
//      → se não existir, retorna erro "missingPreviousMonth" com a lista
//        de meses faltantes desde o último mês presente até o anterior.
//   3. Validação por SKU: exige no mínimo MIN_HISTORY_MONTHS meses para prever
//      → SKUs sem histórico suficiente recebem `insufficientHistory: true`
//        e `historyMonthsAvailable` para o front explicar.
//   4. Coluna "Formato" preservada — Comprados / SGB tratados pelo Python.
// =============================================================================

const results = [];
const WINDOW_OFFSET = 2; // ±2 meses ao redor do mês-alvo
const FORECAST_LENGTH = 3; // mês atual + 2 próximos
const MIN_HISTORY_MONTHS = 2; // mínimo de meses por SKU para prever

// Data de referência define o horizonte
const now = new Date();
const currentYear = now.getFullYear();
const currentMonth = now.getMonth() + 1; // 1-indexado

// Mês anterior (necessário para fazer o mês atual)
const prevMonth = currentMonth === 1 ? 12 : currentMonth - 1;
const prevYear = currentMonth === 1 ? currentYear - 1 : currentYear;
const prevKey = `${prevYear}-${String(prevMonth).padStart(2, "0")}`;

// Próximos N meses começando no atual
const forecastTargets = [];
for (let i = 0; i < FORECAST_LENGTH; i++) {
  let m = currentMonth + i;
  let y = currentYear;
  while (m > 12) {
    m -= 12;
    y++;
  }
  forecastTargets.push({ year: y, month: m });
}

// ── Coleta global de meses presentes para validação do "mês anterior" ──
const allMonthsPresent = new Set();
let maxYearGlobal = 0;
let maxMonthGlobal = 0;

const skuItems = [];
for (const item of $input.all()) {
  const list = item.json.columns || [item.json];
  for (const sku of list) skuItems.push(sku);
}

for (const sku of skuItems) {
  for (const key of Object.keys(sku)) {
    const m = key.match(/^(\d{4})-(\d{2})$/);
    if (!m) continue;
    const v = sku[key];
    if (v == null || v === "" || isNaN(Number(v))) continue;
    allMonthsPresent.add(key);
    const y = parseInt(m[1], 10);
    const mm = parseInt(m[2], 10);
    if (y > maxYearGlobal || (y === maxYearGlobal && mm > maxMonthGlobal)) {
      maxYearGlobal = y;
      maxMonthGlobal = mm;
    }
  }
}

// ── Lista de meses faltantes entre o último presente e o mês anterior ao atual ──
function listMissingBetween(fromY, fromM, toY, toM) {
  const out = [];
  let y = fromY,
    m = fromM + 1;
  while (m > 12) {
    m -= 12;
    y++;
  }
  while (y < toY || (y === toY && m <= toM)) {
    out.push(`${y}-${String(m).padStart(2, "0")}`);
    m++;
    if (m > 12) {
      m = 1;
      y++;
    }
  }
  return out;
}

let missingPreviousMonth = false;
let missingMonths = [];
if (!allMonthsPresent.has(prevKey)) {
  missingPreviousMonth = true;
  if (maxYearGlobal > 0) {
    missingMonths = listMissingBetween(
      maxYearGlobal,
      maxMonthGlobal,
      prevYear,
      prevMonth,
    );
  } else {
    missingMonths = [prevKey];
  }
}

// ── Processa cada SKU ──
for (const sku of skuItems) {
  const skuCode = sku.SKU;
  const description = sku["Descrição"];
  const formato = sku.Formato;

  const salesByYearMonth = {};
  const allYears = new Set();
  const monthsForSku = [];

  for (const key of Object.keys(sku)) {
    const match = key.match(/^(\d{4})-(\d{2})$/);
    if (!match) continue;
    const v = sku[key];
    if (v == null || v === "" || isNaN(Number(v))) continue;
    const year = parseInt(match[1], 10);
    const month = parseInt(match[2], 10);
    allYears.add(year);
    if (!salesByYearMonth[year]) salesByYearMonth[year] = {};
    salesByYearMonth[year][month] = Number(v);
    monthsForSku.push(key);
  }

  monthsForSku.sort();
  const sortedYears = [...allYears].sort((a, b) => a - b);
  const historyMonthsAvailable = monthsForSku.length;
  const insufficientHistory = historyMonthsAvailable < MIN_HISTORY_MONTHS;
  const monthsMissingForMin = Math.max(
    0,
    MIN_HISTORY_MONTHS - historyMonthsAvailable,
  );

  const seasonalWindows = {};

  for (const target of forecastTargets) {
    const targetKey = `${target.year}-${String(target.month).padStart(2, "0")}`;

    const windowMonths = [];
    for (let offset = -WINDOW_OFFSET; offset <= WINDOW_OFFSET; offset++) {
      let wm = target.month + offset;
      if (wm < 1) wm += 12;
      if (wm > 12) wm -= 12;
      windowMonths.push(wm);
    }

    const historicalYears = sortedYears.filter((y) => y < target.year);

    const historicalData = {};
    for (const year of historicalYears) {
      const yearData = {};
      for (const wm of windowMonths) {
        const wmKey = `${year}-${String(wm).padStart(2, "0")}`;
        if (
          salesByYearMonth[year] &&
          salesByYearMonth[year][wm] !== undefined
        ) {
          yearData[wmKey] = salesByYearMonth[year][wm];
        }
      }
      if (Object.keys(yearData).length > 0) historicalData[year] = yearData;
    }

    const targetMonthValues = [];
    for (const year of historicalYears) {
      if (
        salesByYearMonth[year] &&
        salesByYearMonth[year][target.month] !== undefined
      ) {
        targetMonthValues.push({
          year,
          value: salesByYearMonth[year][target.month],
        });
      }
    }

    // Últimos meses consecutivos imediatamente anteriores ao alvo (para SMA / Comprados)
    const recentMonths = [];
    let ry = target.year,
      rm = target.month - 1;
    if (rm < 1) {
      rm = 12;
      ry--;
    }
    for (let i = 0; i < 6; i++) {
      if (salesByYearMonth[ry] && salesByYearMonth[ry][rm] !== undefined) {
        recentMonths.push({
          key: `${ry}-${String(rm).padStart(2, "0")}`,
          value: salesByYearMonth[ry][rm],
        });
      }
      rm--;
      if (rm < 1) {
        rm = 12;
        ry--;
      }
    }

    const values = targetMonthValues.map((v) => v.value);
    const n = values.length;
    const mean = n > 0 ? values.reduce((a, b) => a + b, 0) / n : 0;
    const variance =
      n > 1
        ? values.reduce((sum, v) => sum + Math.pow(v - mean, 2), 0) / (n - 1)
        : 0;
    const stdDev = Math.sqrt(variance);

    const allWindowValues = [];
    for (const year of historicalYears) {
      for (const wm of windowMonths) {
        if (
          salesByYearMonth[year] &&
          salesByYearMonth[year][wm] !== undefined
        ) {
          allWindowValues.push(salesByYearMonth[year][wm]);
        }
      }
    }
    const windowN = allWindowValues.length;
    const windowMean =
      windowN > 0 ? allWindowValues.reduce((a, b) => a + b, 0) / windowN : 0;
    const windowVariance =
      windowN > 1
        ? allWindowValues.reduce(
            (sum, v) => sum + Math.pow(v - windowMean, 2),
            0,
          ) /
          (windowN - 1)
        : 0;
    const windowStdDev = Math.sqrt(windowVariance);

    seasonalWindows[targetKey] = {
      windowMonths: windowMonths.map((m) => String(m).padStart(2, "0")),
      historicalYears,
      historicalData,
      targetMonthHistory: targetMonthValues,
      recentMonths,
      statistics: {
        mean: parseFloat(mean.toFixed(3)),
        stdDev: parseFloat(stdDev.toFixed(3)),
        confidenceInterval: {
          lower: parseFloat(Math.max(0, mean - stdDev).toFixed(3)),
          upper: parseFloat((mean + stdDev).toFixed(3)),
        },
        sampleSize: n,
      },
      windowStatistics: {
        mean: parseFloat(windowMean.toFixed(3)),
        stdDev: parseFloat(windowStdDev.toFixed(3)),
        sampleSize: windowN,
      },
    };
  }

  results.push({
    SKU: skuCode,
    Descrição: description,
    Formato: formato,
    dataReferencia: now.toISOString().split("T")[0],
    historyMonthsAvailable,
    insufficientHistory,
    monthsMissingForMin,
    seasonalWindows,
  });
}

return {
  analysis: results,
  forecastTargets: forecastTargets.map(
    (t) => `${t.year}-${String(t.month).padStart(2, "0")}`,
  ),
  validation: {
    missingPreviousMonth,
    expectedPreviousMonth: prevKey,
    missingMonths,
    lastHistoryMonth:
      maxYearGlobal > 0
        ? `${maxYearGlobal}-${String(maxMonthGlobal).padStart(2, "0")}`
        : null,
    minHistoryMonths: MIN_HISTORY_MONTHS,
  },
};

