# =============================================================================
# seasonal_forecast.py — v2
# Previsão de Vendas — Ensemble Determinístico (3 Métodos) + extensões
#
# MUDANÇAS desta versão:
#   1. Respeita `insufficientHistory` (vindo do JS): retorna previsoes vazias
#      com motivo "historico_insuficiente".
#   2. Trata `Formato`:
#        - "Comprados" → Média Móvel Simples dos últimos 3 meses
#                        (lead time 20-30 dias do dept de compras)
#        - "SGB"       → mesmo ensemble, mas com flag `tipo: "SGB"`
#                        (Private Label — previsão externa "furada")
#        - outros      → ensemble (heurística + SES + tendência sazonal)
#   3. `tolerancePct`: tolerância ± em % baseada em stdDev/mean (CV).
#   4. `intervaloConfianca` ajustado em torno da PREVISÃO usando tolerância.
# =============================================================================


def _mean(vals):
    return sum(vals) / len(vals) if vals else 0.0


def _pop_std(vals):
    if len(vals) < 2:
        return 0.0
    m = _mean(vals)
    return (sum((v - m) ** 2 for v in vals) / len(vals)) ** 0.5


def _recency_weights(n):
    if n <= 0:
        return []
    if n == 1:
        return [4.0]
    if n == 2:
        return [2.0, 4.0]
    if n == 3:
        return [2.0, 2.0, 4.0]
    return [1.0] + [2.0] * (n - 2) + [4.0]


def _weighted_mean(vals, weights):
    tw = sum(weights)
    if tw == 0:
        return _mean(vals)
    return sum(v * w for v, w in zip(vals, weights)) / tw


def _ols(xs, ys):
    n = len(xs)
    if n < 2:
        return (_mean(ys), 0.0)
    mx = _mean(xs); my = _mean(ys)
    num = sum((x - mx) * (y - my) for x, y in zip(xs, ys))
    den = sum((x - mx) ** 2 for x in xs)
    if abs(den) < 1e-12:
        return (my, 0.0)
    b = num / den
    return (my - b * mx, b)


def _judge_heuristic(values, trend_blend=0.7):
    n = len(values)
    if n == 0: return 0.0
    if n == 1: return values[0]
    w_avg = _weighted_mean(values, _recency_weights(n))
    ratios = [values[i + 1] / values[i] for i in range(n - 1) if values[i] > 0]
    if len(ratios) >= 2:
        trend_ratio = 0.3 * ratios[0] + 0.7 * ratios[-1]
    elif ratios:
        trend_ratio = ratios[0]
    else:
        trend_ratio = 1.0
    trend_forecast = max(0.0, values[-1] * trend_ratio)
    hist_mean = _mean(values)
    cv = _pop_std(values) / hist_mean if hist_mean > 0 else 0.0
    cv_factor = min(cv, 1.0)
    adaptive = trend_blend * (1.0 - cv_factor * 0.6)
    if hist_mean > 0 and values[-1] / hist_mean < 0.3:
        adaptive *= 0.3
    anchor = cv_factor * hist_mean + (1.0 - cv_factor) * w_avg
    return max(0.0, adaptive * trend_forecast + (1.0 - adaptive) * anchor)


def _judge_ses(values):
    n = len(values)
    if n == 0: return 0.0
    if n == 1: return values[0]
    best_error = float("inf"); best_level = values[-1]
    for alpha_x10 in range(1, 10):
        alpha = alpha_x10 / 10.0
        level = values[0]; error = 0.0
        for i in range(1, n):
            error += (values[i] - level) ** 2
            level = alpha * values[i] + (1.0 - alpha) * level
        if error < best_error:
            best_error = error; best_level = level
    return max(0.0, best_level)


def _judge_window_trend(values, years, hist_data):
    n = len(values)
    if n == 0: return 0.0
    if n == 1: return values[0]
    window_means = []; valid_years = []
    for yr in years:
        yk = str(yr)
        if yk in hist_data:
            wv = list(hist_data[yk].values())
            if wv:
                window_means.append(_mean(wv)); valid_years.append(yr)
    if len(window_means) < 2:
        return max(0.0, _weighted_mean(values, _recency_weights(n)))
    forecast_year = max(years) + 1
    a, b = _ols(valid_years, window_means)
    predicted_window_mean = a + b * forecast_year
    seasonal_ratios = []
    for i, yr in enumerate(years):
        yk = str(yr)
        if yk in hist_data:
            wv = list(hist_data[yk].values())
            wm = _mean(wv)
            if wm > 0:
                seasonal_ratios.append(values[i] / wm)
    seasonal_ratio = _weighted_mean(seasonal_ratios, _recency_weights(len(seasonal_ratios))) if seasonal_ratios else 1.0
    result = predicted_window_mean * seasonal_ratio
    if result <= 0:
        return max(0.0, _weighted_mean(values, _recency_weights(n)))
    return max(0.0, result)


def _backtest_weights(values, years, hist_data):
    n = len(values)
    if n < 3:
        return [1.0 / 3, 1.0 / 3, 1.0 / 3]
    train_vals = values[:-1]; train_years = years[:-1]
    actual = values[-1]
    last_year_key = str(years[-1])
    train_hist = {k: v for k, v in hist_data.items() if k != last_year_key}
    preds = [
        _judge_heuristic(train_vals),
        _judge_ses(train_vals),
        _judge_window_trend(train_vals, train_years, train_hist),
    ]
    errors = [abs(actual - p) for p in preds]
    epsilon = max(1.0, actual * 0.05)
    inv_errors = [1.0 / (e + epsilon) for e in errors]
    total = sum(inv_errors)
    return [w / total for w in inv_errors]


def _forecast_target(values, years, hist_data):
    pred_h = _judge_heuristic(values)
    pred_s = _judge_ses(values)
    pred_t = _judge_window_trend(values, years, hist_data)
    weights = _backtest_weights(values, years, hist_data)
    prediction = pred_h * weights[0] + pred_s * weights[1] + pred_t * weights[2]
    return {
        "previsao": max(0.0, round(prediction, 3)),
        "metodos": {
            "heuristica": round(pred_h, 3),
            "suavizacaoExponencial": round(pred_s, 3),
            "tendenciaSazonal": round(pred_t, 3),
        },
        "pesos": {
            "heuristica": round(weights[0], 3),
            "suavizacaoExponencial": round(weights[1], 3),
            "tendenciaSazonal": round(weights[2], 3),
        },
    }


def _confidence_label(sample_size, cv_factor):
    if sample_size < 3: return "baixa"
    if cv_factor > 0.5: return "média"
    return "alta"


def _tolerance_pct(values, prediction):
    """Tolerância ± em % com base no CV; mínimo 10%, máximo 60%."""
    if not values or prediction <= 0:
        return 30.0
    m = _mean(values)
    if m <= 0:
        return 30.0
    cv = _pop_std(values) / m
    pct = round(cv * 100.0, 1)
    if pct < 10.0: pct = 10.0
    if pct > 60.0: pct = 60.0
    return pct


def _moving_average_3(window):
    """Para SKUs Comprados: média simples dos meses recentes (até 3)."""
    recent = window.get("recentMonths", [])
    if not recent:
        # fallback: usar histórico do mês alvo
        tmh = window.get("targetMonthHistory", [])
        vals = [e["value"] for e in tmh]
        return _mean(vals)
    vals = [r["value"] for r in recent[:3]]
    return _mean(vals)


def seasonal_forecast(sku_data):
    formato = (sku_data.get("Formato") or "").strip()
    formato_norm = formato.lower()

    base = {
        "SKU": sku_data.get("SKU"),
        "Descrição": sku_data.get("Descrição", ""),
        "Formato": formato,
        "dataReferencia": sku_data.get("dataReferencia", ""),
        "historyMonthsAvailable": sku_data.get("historyMonthsAvailable", 0),
        "insufficientHistory": bool(sku_data.get("insufficientHistory", False)),
        "monthsMissingForMin": sku_data.get("monthsMissingForMin", 0),
    }

    windows = sku_data.get("seasonalWindows", {}) or {}

    # Curto-circuito: histórico insuficiente
    if base["insufficientHistory"]:
        previsoes = []
        for target_month in sorted(windows.keys()):
            previsoes.append({
                "mes": target_month,
                "previsao": 0.0,
                "tolerancePct": 0.0,
                "intervaloConfianca": {"lower": 0.0, "upper": 0.0},
                "confianca": "baixa",
                "motivo": "historico_insuficiente",
                "tipo": "ensemble",
            })
        base["previsoes"] = previsoes
        return base

    previsoes = []
    is_comprados = formato_norm == "comprados"
    is_sgb       = formato_norm == "sgb"

    for target_month in sorted(windows.keys()):
        window = windows[target_month]
        target_history = window.get("targetMonthHistory", [])
        stats = window.get("statistics", {})
        hist_data = window.get("historicalData", {})

        values = [entry["value"] for entry in target_history]
        years  = [entry["year"]  for entry in target_history]

        hist_mean = _mean(values) if values else 0.0
        cv = _pop_std(values) / hist_mean if hist_mean > 0 else 0.0
        cv_factor = min(cv, 1.0)

        if is_comprados:
            previsao = round(max(0.0, _moving_average_3(window)), 3)
            recent_vals = [r["value"] for r in window.get("recentMonths", [])[:3]]
            tol = _tolerance_pct(recent_vals, previsao)
            previsoes.append({
                "mes": target_month,
                "previsao": previsao,
                "tolerancePct": tol,
                "intervaloConfianca": {
                    "lower": round(max(0.0, previsao * (1 - tol / 100.0)), 3),
                    "upper": round(previsao * (1 + tol / 100.0), 3),
                },
                "confianca": _confidence_label(len(recent_vals), cv_factor),
                "tipo": "comprados_sma3",
                "metodos": {"mediaMovel3": previsao},
                "pesos": {"mediaMovel3": 1.0},
            })
            continue

        if not values:
            previsoes.append({
                "mes": target_month,
                "previsao": 0.0,
                "tolerancePct": 0.0,
                "intervaloConfianca": {"lower": 0.0, "upper": 0.0},
                "confianca": "baixa",
                "tipo": "sgb" if is_sgb else "ensemble",
                "motivo": "sem_historico_no_mes_alvo",
            })
            continue

        fc = _forecast_target(values, years, hist_data)
        tol = _tolerance_pct(values, fc["previsao"])
        previsoes.append({
            "mes": target_month,
            "previsao": fc["previsao"],
            "tolerancePct": tol,
            "intervaloConfianca": {
                "lower": round(max(0.0, fc["previsao"] * (1 - tol / 100.0)), 3),
                "upper": round(fc["previsao"] * (1 + tol / 100.0), 3),
            },
            "confianca": _confidence_label(stats.get("sampleSize", 0), cv_factor),
            "tipo": "sgb" if is_sgb else "ensemble",
            "metodos": fc["metodos"],
            "pesos": fc["pesos"],
        })

    base["previsoes"] = previsoes
    return base


# ─── n8n bridge ───
_results = []
_validation = None
_forecast_targets = None
_target_months = None

for _item in _items:
    _d = _item["json"]
    _skus = _d.get("analysis")
    if _skus is None:
        _skus = [_d]
    if _validation is None:
        _validation = _d.get("validation")
    if _forecast_targets is None:
        _forecast_targets = _d.get("forecastTargets")
    if _target_months is None:
        _target_months = _d.get("targetMonths")
    for _sku in _skus:
        _row = seasonal_forecast(_sku)
        # Backtest passthrough
        if "backtestTarget" in _sku:
            _row["backtestTarget"] = _sku["backtestTarget"]
        if "realValue" in _sku:
            _row["realValue"] = _sku["realValue"]
        if _validation is not None:
            _row["_validation"] = _validation
        if _forecast_targets is not None:
            _row["_forecastTargets"] = _forecast_targets
        if _target_months is not None:
            _row["_targetMonths"] = _target_months
        _results.append({"json": _row})

return _results

