// =============================================================================
// Response — v2
// Junta os itens do Parse Data num envelope { data, createdAt, validation,
// forecastTargets } para o cache Redis.
// =============================================================================

const items = $input.all().map((d) => d.json);

let validation = null;
let forecastTargets = null;

const data = items.map((it) => {
  if (it._validation) validation = it._validation;
  if (it._forecastTargets) forecastTargets = it._forecastTargets;
  const { _validation, _forecastTargets, ...rest } = it;
  return rest;
});

return {
  data,
  createdAt: $now,
  validation,
  forecastTargets,
};

// =============================================================================
// Parse Data — v2
// Formata o output do Python para a planilha de saída + payload de resposta.
//
// Mantém compatibilidade com o front: cada linha tem SKU, Descrição e colunas
// YYYY-MM com o número da previsão. Acrescenta metadados que o front pode
// consumir (tolerancePct, insufficientHistory, formato, validation global).
// =============================================================================

const results = [];

let validation = null;
let forecastTargets = null;

for (const item of $input.all()) {
  const data = item.json;
  if (!validation && data._validation) validation = data._validation;
  if (!forecastTargets && data._forecastTargets)
    forecastTargets = data._forecastTargets;

  const row = {
    SKU: data.SKU,
    Descrição: data["Descrição"],
    Formato: data.Formato || "",
    insufficientHistory: !!data.insufficientHistory,
    historyMonthsAvailable: data.historyMonthsAvailable || 0,
    monthsMissingForMin: data.monthsMissingForMin || 0,
    detalhes: {},
  };

  for (const prev of data.previsoes || []) {
    row[prev.mes] = prev.previsao;
    row.detalhes[prev.mes] = {
      previsao: prev.previsao,
      tolerancePct: prev.tolerancePct,
      intervaloConfianca: prev.intervaloConfianca,
      confianca: prev.confianca,
      tipo: prev.tipo,
      motivo: prev.motivo || null,
    };
  }

  results.push({ json: row });
}

// Anexa validação global no primeiro item (se houver)
if (results.length > 0 && validation) {
  results[0].json._validation = validation;
  results[0].json._forecastTargets = forecastTargets;
}

return results;

// Excel Rows — strip metadata fields before xlsx serialization.
// Keeps only SKU, Descrição and the YYYY-MM forecast columns.

return $json.data.map((item) => {
  const row = { SKU: item.SKU, Descrição: item["Descrição"] };
  for (const k of Object.keys(item)) {
    if (/^\d{4}-\d{2}$/.test(k)) row[k] = item[k];
  }
  return { json: row };
});
